class TransactionProcessor:
    def __init__(self, cfg: ConsumerConfig):
        self.cfg = cfg
        self.log = logging.getLogger("tx.processor")
        self.handler_registry: Dict[str, Callable[..., Any]] = {}
        self._stop = threading.Event()
        self._idempotency = IdempotencyCache(cfg.idempotency_ttl_sec) if cfg.enforce_idempotency else None

    def register_handler(self, key: str, handler: Callable[..., Any]) -> None:
        self.handler_registry[key] = handler

    def stop(self) -> None:
        self._stop.set()

    def stopped(self) -> bool:
        return self._stop.is_set()

    def process(self, event: Any, context: Dict[str, Any]) -> Any:
        if self._idempotency is not None:
            ev_id = None
            if isinstance(event, dict):
                ev_id = event.get(self.cfg.id_field) or event.get("id")
            if ev_id is not None:
                ev_id_str = str(ev_id)
                if self._idempotency.seen(ev_id_str):
                    self.log.info("Idempotent skip event_id=%s topic=%s partition=%s offset=%s",
                                  ev_id_str, context.get("topic"), context.get("partition"), context.get("offset"))
                    return {"status": "skipped", "reason": "idempotent", "event_id": ev_id_str}

        if isinstance(event, dict) and event.get("domain") == "transaction":
            validate_transaction_event(event)

        handler = resolve_handler(event, self.cfg, self.handler_registry)
        result = handler(event=event, context=context)

        if self._idempotency is not None:
            if isinstance(event, dict):
                ev_id = event.get(self.cfg.id_field) or event.get("id")
                if ev_id is not None:
                    self._idempotency.mark(str(ev_id))

        return result


